200	                if !interactive {
201	                    let remaining = self.max_instrs.saturating_sub(session.instructions());
202	                    if remaining == 0 {
203	                        self.budget_exhausted = true;
204	                        let instrs = session.instructions();
205	                        self.finish(format!("halted (budget) -- {} instrs", instrs), true);
206	                        return true;
207	                    }
208	                }
209	                let result = session.tick();
210	                if session.is_awaiting_input() {
211	                    self.awaiting_input = true;
212	                    self.output = session.output();
213	                    self.elapsed_ms = now_ms() - self.started_at;
