228	                            reason,
229	                            instrs,
230	                            now_ms() - self.started_at
231	                        ),
232	                        !halted,
233	                    );
234	                } else {
235	                    self.output = session.output();
236	                    self.elapsed_ms = now_ms() - self.started_at;
237	                    self.status = format!(
238	                        "running... {} instrs, {:.0} ms",
239	                        session.instructions(),
240	                        self.elapsed_ms
241	                    );
242	                    self.schedule_tick(ctx);
243	                }
