264	                if e.key() == "Enter" && (e.ctrl_key() || e.meta_key()) {
265	                    e.prevent_default();
266	                    ctx.link().send_message(Msg::Run);
267	                } else if e.key() == "Escape" && self.running {
268	                    e.prevent_default();
