use gloo::timers::callback::Timeout;
use web_sys::{Element, HtmlInputElement, HtmlSelectElement, HtmlTextAreaElement, KeyboardEvent};
use yew::prelude::*;

pub mod config;
pub mod demos;
pub mod runner;

use demos::{DEMOS, default_demo_index};
use runner::Session;

const DEFAULT_MAX_INSTRS: u64 = 200_000_000;
const TICK_DELAY_MS: u32 = 0;

fn now_ms() -> f64 {
    js_sys::Date::now()
}

pub enum Msg {
    SelectDemo(usize),
    SourceChanged(String),
    Run,
    Tick,
    Stop,
    Reset,
    Clear,
    IncreaseBudget,
    KeyDown(KeyboardEvent),
    InputChanged(String),
    InputSubmit,
}

pub struct App {
    selected: usize,
    source: String,
    output: String,
    status: String,
    error: bool,
    session: Option<Session>,
    running: bool,
    max_instrs: u64,
    started_at: f64,
    elapsed_ms: f64,
    budget_exhausted: bool,
    input_line: String,
    awaiting_input: bool,
    output_ref: NodeRef,
    input_ref: NodeRef,
}

impl App {
    fn load_demo(&mut self, idx: usize) {
        if let Some(demo) = DEMOS.get(idx) {
            self.selected = idx;
            self.source = demo.source.to_string();
            self.output.clear();
            self.status = "idle".into();
            self.error = false;
            self.session = None;
            self.running = false;
            self.budget_exhausted = false;
            self.elapsed_ms = 0.0;
            self.input_line.clear();
            self.awaiting_input = false;
        }
    }

    fn start_run(&mut self, ctx: &Context<Self>) {
        let interactive = DEMOS
            .get(self.selected)
            .map(|d| d.interactive)
            .unwrap_or(false);
        self.session = Some(if interactive {
            Session::new_interactive(&self.source)
        } else {
            Session::new(&self.source)
        });
        self.input_line.clear();
        self.awaiting_input = false;
        self.running = true;
        self.error = false;
        self.budget_exhausted = false;
        self.output.clear();
        self.started_at = now_ms();
        self.elapsed_ms = 0.0;
        self.status = "running...".into();
        self.schedule_tick(ctx);
    }

    fn schedule_tick(&self, ctx: &Context<Self>) {
        let link = ctx.link().clone();
        Timeout::new(TICK_DELAY_MS, move || link.send_message(Msg::Tick)).forget();
    }

    fn finish(&mut self, status: String, error: bool) {
        self.running = false;
        self.status = status;
        self.error = error;
        self.elapsed_ms = now_ms() - self.started_at;
        if let Some(s) = &self.session {
            let raw = s.output();
            self.output = raw;
        }
    }
}

impl Component for App {
    type Message = Msg;
    type Properties = ();

    fn create(_ctx: &Context<Self>) -> Self {
        let idx = default_demo_index();
        let demo = &DEMOS[idx];
        Self {
            selected: idx,
            source: demo.source.to_string(),
            output: String::new(),
            status: "idle".into(),
            error: false,
            session: None,
            running: false,
            max_instrs: DEFAULT_MAX_INSTRS,
            started_at: 0.0,
            elapsed_ms: 0.0,
            budget_exhausted: false,
            input_line: String::new(),
            awaiting_input: false,
            output_ref: NodeRef::default(),
            input_ref: NodeRef::default(),
        }
    }

    fn rendered(&mut self, _ctx: &Context<Self>, _first_render: bool) {
        if let Some(el) = self.output_ref.cast::<Element>() {
            el.set_scroll_top(el.scroll_height());
        }
        if self.awaiting_input
            && let Some(el) = self.input_ref.cast::<HtmlInputElement>()
        {
            let _ = el.focus();
        }
    }

    fn update(&mut self, ctx: &Context<Self>, msg: Self::Message) -> bool {
        match msg {
            Msg::SelectDemo(i) => {
                self.load_demo(i);
                self.max_instrs = DEFAULT_MAX_INSTRS;
                true
            }
            Msg::SourceChanged(v) => {
                self.source = v;
                false
            }
            Msg::Run => {
                self.max_instrs = DEFAULT_MAX_INSTRS;
                self.start_run(ctx);
                true
            }
            Msg::IncreaseBudget => {
                self.max_instrs = self.max_instrs.saturating_mul(4);
                self.start_run(ctx);
                true
            }
            Msg::Stop => {
                if self.running {
                    self.finish("stopped".into(), false);
                }
                true
            }
            Msg::Reset => {
                let idx = self.selected;
                self.running = false;
                self.session = None;
                self.load_demo(idx);
                self.max_instrs = DEFAULT_MAX_INSTRS;
                true
            }
            Msg::Clear => {
                self.output.clear();
                if !self.running {
                    self.status = "idle".into();
                    self.error = false;
                    self.budget_exhausted = false;
                }
                true
            }
            Msg::Tick => {
                if !self.running {
                    return false;
                }
                let Some(session) = self.session.as_mut() else {
                    self.running = false;
                    return true;
                };
                let interactive = DEMOS
                    .get(self.selected)
                    .map(|d| d.interactive)
                    .unwrap_or(false);
                if !interactive {
                    let remaining = self.max_instrs.saturating_sub(session.instructions());
                    if remaining == 0 {
                        self.budget_exhausted = true;
                        let instrs = session.instructions();
                        self.finish(format!("halted (budget) -- {} instrs", instrs), true);
                        return true;
                    }
                }
                let result = session.tick();
                if session.is_awaiting_input() {
                    self.awaiting_input = true;
                    self.output = session.output();
                    self.elapsed_ms = now_ms() - self.started_at;
                    self.status = format!(
                        "awaiting input ({} instrs, {:.0} ms)",
                        session.instructions(),
                        self.elapsed_ms
                    );
                    return true;
                }
                if result.done {
                    let instrs = session.instructions();
                    let reason = session.stop_reason();
                    let halted = session.is_halted();
                    self.finish(
                        format!(
                            "{} ({} instrs, {:.0} ms)",
                            reason,
                            instrs,
                            now_ms() - self.started_at
                        ),
                        !halted,
                    );
                } else {
                    self.output = session.output();
                    self.elapsed_ms = now_ms() - self.started_at;
                    self.status = format!(
                        "running... {} instrs, {:.0} ms",
                        session.instructions(),
                        self.elapsed_ms
                    );
                    self.schedule_tick(ctx);
                }
                true
            }
            Msg::InputChanged(v) => {
                self.input_line = v;
                false
            }
            Msg::InputSubmit => {
                if !self.awaiting_input {
                    return false;
                }
                let line = std::mem::take(&mut self.input_line);
                if let Some(session) = self.session.as_mut() {
                    session.feed_input(&line);
                }
                self.awaiting_input = false;
                self.status = "running...".into();
                self.schedule_tick(ctx);
                true
            }
            Msg::KeyDown(e) => {
                if e.key() == "Enter" && (e.ctrl_key() || e.meta_key()) {
                    e.prevent_default();
                    ctx.link().send_message(Msg::Run);
                } else if e.key() == "Escape" && self.running {
                    e.prevent_default();
                    ctx.link().send_message(Msg::Stop);
                }
                false
            }
        }
    }

